'use client';

import { useCallback, useMemo } from 'react';
import {
  Background,
  BackgroundVariant,
  Connection,
  Controls,
  Handle,
  MarkerType,
  MiniMap,
  Node,
  NodeProps,
  Position,
  ReactFlow,
  ReactFlowProvider,
  addEdge,
  useEdgesState,
  useNodesState,
  useReactFlow,
} from 'reactflow';
import 'reactflow/dist/style.css';
import {
  BrushCleaning,
  ImageIcon,
  Plus,
  Search,
  Settings2,
  Sparkles,
} from 'lucide-react';

type BrainstormNodeData = {
  badge: string;
  title: string;
  channel: string;
  bullets: string[];
  accent: string;
};

const initialNodes: Node<BrainstormNodeData>[] = [
  {
    id: 'node-hook',
    type: 'idea',
    position: { x: 120, y: 120 },
    data: {
      badge: 'Campaign Hook',
      title: '30-day creator sprint for indie founders',
      channel: 'LinkedIn thought-starter',
      bullets: [
        'Open with a polarizing founder truth',
        'Turn milestones into a daily accountability arc',
        'End with a prompt for audience participation',
      ],
      accent: 'from-amber-100 via-white to-rose-50',
    },
  },
  {
    id: 'node-carousel',
    type: 'idea',
    position: { x: 500, y: 260 },
    data: {
      badge: 'Format Angle',
      title: 'Carousel: lessons from shipping in public',
      channel: 'Instagram / LinkedIn carousel',
      bullets: [
        'Slide 1 headline with one surprising metric',
        'Slides 2-6 pair mistake -> lesson -> proof',
        'Last slide converts into a saveable checklist',
      ],
      accent: 'from-sky-100 via-white to-cyan-50',
    },
  },
  {
    id: 'node-reel',
    type: 'idea',
    position: { x: 860, y: 110 },
    data: {
      badge: 'Video Prompt',
      title: 'Fast-talking reel: “3 content myths I stopped believing”',
      channel: 'TikTok / Reels voiceover',
      bullets: [
        'Use quick cuts tied to one myth each',
        'Overlay contrarian captions with proof snippets',
        'Close with a CTA to comment “template”',
      ],
      accent: 'from-emerald-100 via-white to-lime-50',
    },
  },
];

const initialEdges = [
  {
    id: 'edge-hook-carousel',
    source: 'node-hook',
    target: 'node-carousel',
    animated: true,
    markerEnd: { type: MarkerType.ArrowClosed },
    style: { stroke: '#94a3b8', strokeWidth: 1.5 },
  },
  {
    id: 'edge-carousel-reel',
    source: 'node-carousel',
    target: 'node-reel',
    markerEnd: { type: MarkerType.ArrowClosed },
    style: { stroke: '#94a3b8', strokeWidth: 1.5 },
  },
];

function IdeaNode({ data, selected }: NodeProps<BrainstormNodeData>) {
  return (
    <div
      className={[
        'w-80 rounded-3xl border border-slate-200/80 bg-gradient-to-br p-4 shadow-[0_18px_50px_-30px_rgba(15,23,42,0.35)] transition-all duration-200',
        selected ? 'scale-[1.01] border-slate-300 shadow-[0_24px_60px_-32px_rgba(15,23,42,0.42)]' : '',
        data.accent,
      ].join(' ')}
    >
      <Handle
        type="target"
        position={Position.Top}
        className="!size-3 !border-2 !border-white !bg-slate-400"
      />
      <div className="flex flex-col gap-4">
        <div className="flex items-start justify-between gap-3">
          <div className="flex flex-col gap-2">
            <span className="inline-flex w-fit items-center rounded-full border border-slate-200 bg-white/80 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-600 backdrop-blur">
              {data.badge}
            </span>
            <div className="flex items-start gap-3">
              <div className="flex size-10 items-center justify-center rounded-2xl border border-slate-200 bg-white/85 text-slate-700 shadow-sm">
                <Sparkles className="size-4" />
              </div>
              <div className="flex flex-col gap-1">
                <h3 className="text-base font-semibold leading-6 text-slate-900">
                  {data.title}
                </h3>
                <p className="text-sm text-slate-500">{data.channel}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="rounded-2xl border border-white/80 bg-white/75 p-3 backdrop-blur-sm">
          <ul className="flex flex-col gap-2 text-sm leading-6 text-slate-600">
            {data.bullets.map((bullet) => (
              <li key={bullet} className="flex gap-2">
                <span className="mt-2 size-1.5 rounded-full bg-slate-300" />
                <span>{bullet}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>

      <Handle
        type="source"
        position={Position.Bottom}
        className="!size-3 !border-2 !border-white !bg-slate-400"
      />
    </div>
  );
}

function FlowCanvas() {
  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);
  const { screenToFlowPosition } = useReactFlow();

  const nodeTypes = useMemo(() => ({ idea: IdeaNode }), []);

  const onConnect = useCallback(
    (connection: Connection) => {
      setEdges((currentEdges) =>
        addEdge(
          {
            ...connection,
            animated: true,
            markerEnd: { type: MarkerType.ArrowClosed },
            style: { stroke: '#94a3b8', strokeWidth: 1.5 },
          },
          currentEdges,
        ),
      );
    },
    [setEdges],
  );

  const handleAddNode = useCallback(() => {
    const id = `node-${Date.now()}`;
    const position = screenToFlowPosition({
      x: window.innerWidth / 2,
      y: window.innerHeight / 2,
    });

    setNodes((currentNodes) => [
      ...currentNodes,
      {
        id,
        type: 'idea',
        position,
        data: {
          badge: 'Quick Note',
          title: `Fresh concept ${currentNodes.length - 2}`,
          channel: 'Untitled draft',
          bullets: [
            'Capture a strong opening line',
            'Define the content format and emotional angle',
            'Add a CTA worth responding to',
          ],
          accent: 'from-violet-100 via-white to-fuchsia-50',
        },
      },
    ]);
  }, [screenToFlowPosition, setNodes]);

  const tools = [
    { label: 'Add note', icon: Plus, onClick: handleAddNode, primary: true },
    { label: 'Draw', icon: BrushCleaning },
    { label: 'Image', icon: ImageIcon },
    { label: 'Search', icon: Search },
    { label: 'Settings', icon: Settings2 },
  ];

  return (
    <div className="relative h-[100dvh] overflow-hidden bg-[radial-gradient(circle_at_top,_rgba(240,249,255,0.95),_rgba(248,250,252,1)_45%,_rgba(255,255,255,1)_100%)] text-slate-900">
      <header className="pointer-events-none fixed inset-x-0 top-0 z-20 flex justify-center px-4 pt-4">
        <div className="pointer-events-auto flex w-full max-w-5xl items-center justify-between rounded-full border border-white/70 bg-white/88 px-4 py-3 shadow-[0_18px_45px_-28px_rgba(15,23,42,0.35)] backdrop-blur-xl">
          <div className="flex items-center gap-3">
            <div className="flex size-10 items-center justify-center rounded-2xl border border-slate-200 bg-slate-50 shadow-sm">
              <Sparkles className="size-4 text-slate-700" />
            </div>
            <div>
              <p className="text-sm font-semibold text-slate-900">
                Social Content Lab
              </p>
              <p className="text-xs text-slate-500">
                Map ideas before generating copy
              </p>
            </div>
          </div>

          <nav className="flex items-center gap-2 rounded-full border border-slate-200/80 bg-slate-50/80 p-1">
            <span className="rounded-full bg-slate-900 px-3 py-2 text-xs font-semibold tracking-[0.16em] text-white">
              1. BRAINSTORMING
            </span>
            <span className="rounded-full px-3 py-2 text-xs font-medium tracking-[0.16em] text-slate-400">
              2. CHOICE
            </span>
            <span className="rounded-full px-3 py-2 text-xs font-medium tracking-[0.16em] text-slate-400">
              3. GENERATING
            </span>
          </nav>
        </div>
      </header>

      <main className="h-full pt-24">
        <ReactFlow
          nodes={nodes}
          edges={edges}
          nodeTypes={nodeTypes}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          fitView
          fitViewOptions={{ padding: 0.2 }}
          defaultEdgeOptions={{
            animated: true,
            markerEnd: { type: MarkerType.ArrowClosed },
            style: { stroke: '#94a3b8', strokeWidth: 1.5 },
          }}
          proOptions={{ hideAttribution: true }}
          className="!bg-transparent"
        >
          <Background
            variant={BackgroundVariant.Dots}
            gap={20}
            size={1.2}
            color="#cbd5e1"
          />
          <Controls
            position="top-right"
            className="!top-4 !right-4 !rounded-2xl !border !border-slate-200 !bg-white/90 !shadow-lg !backdrop-blur"
          />
          <MiniMap
            pannable
            zoomable
            nodeColor={() => '#e2e8f0'}
            className="!bottom-24 !rounded-2xl !border !border-slate-200 !bg-white/90 !shadow-lg !backdrop-blur"
          />
        </ReactFlow>
      </main>

      <div className="pointer-events-none fixed inset-x-0 bottom-0 z-20 flex justify-center px-4 pb-6">
        <div className="pointer-events-auto flex items-center gap-2 rounded-full border border-white/70 bg-white/80 p-2 shadow-[0_24px_60px_-30px_rgba(15,23,42,0.35)] backdrop-blur-xl">
          {tools.map(({ label, icon: Icon, onClick, primary }) => (
            <button
              key={label}
              type="button"
              onClick={onClick}
              className={[
                'group flex items-center gap-2 rounded-full px-4 py-3 text-sm font-medium text-slate-600 transition duration-200 hover:scale-[1.03] hover:bg-slate-50 hover:text-slate-900 active:scale-[0.98]',
                primary ? 'bg-slate-900 text-white hover:bg-slate-800 hover:text-white' : '',
              ].join(' ')}
            >
              <Icon className="size-4 transition-opacity duration-200 group-hover:opacity-90" />
              <span className="hidden sm:inline">{label}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

export default function Home() {
  return (
    <ReactFlowProvider>
      <FlowCanvas />
    </ReactFlowProvider>
  );
}

