import type { Edge, Node } from 'reactflow';

export type CanvasNodeKind =
  | 'brainstorm'
  | 'asset'
  | 'generation'
  | 'research'
  | 'image-stack'
  | 'template';

export type MediaType = 'image' | 'video' | 'document';

export type CanvasMediaItem = {
  label: string;
  type: MediaType;
  meta: string;
};

export type CanvasStackItem = {
  label: string;
  tint: string;
};

export type CanvasNodeData = {
  kind: CanvasNodeKind;
  badge: string;
  title: string;
  subtitle: string;
  accent: string;
  body?: string;
  bullets?: string[];
  chips?: string[];
  prompt?: string;
  mediaItems?: CanvasMediaItem[];
  stackItems?: CanvasStackItem[];
};

export type CanvasNode = Node<CanvasNodeData>;
export type CanvasEdge = Edge;

import { MarkerType } from 'reactflow';

import type { CanvasEdge, CanvasNode, CanvasNodeData } from './types';

const defaultEdgeStyle = {
  stroke: '#94a3b8',
  strokeWidth: 1.5,
};

export const edgeDefaults = {
  animated: true,
  markerEnd: { type: MarkerType.ArrowClosed },
  style: defaultEdgeStyle,
};

function createNode(
  id: string,
  position: { x: number; y: number },
  data: CanvasNodeData,
): CanvasNode {
  return {
    id,
    type: 'canvas-card',
    position,
    data,
  };
}

export const initialNodes: CanvasNode[] = [
  createNode('node-hook', { x: 80, y: 130 }, {
    kind: 'brainstorm',
