'use client';

import {
  Globe,
  Library,
  Paperclip,
  Plus,
  Sparkles,
  type LucideIcon,
} from 'lucide-react';

type ToolbarAction = {
  label: string;
  icon: LucideIcon;
  onClick: () => void;
  primary?: boolean;
};

type FloatingToolbarProps = {
  onAddNote: () => void;
  onAddOwnContent: () => void;
  onGenerate: () => void;
  onScrape: () => void;
  onTemplate: () => void;
};

export function FloatingToolbar({
  onAddNote,
  onAddOwnContent,
  onGenerate,
  onScrape,
  onTemplate,
}: FloatingToolbarProps) {
  const actions: ToolbarAction[] = [
    { label: 'Add note', icon: Plus, onClick: onAddNote, primary: true },
    { label: 'Own content', icon: Paperclip, onClick: onAddOwnContent },
    { label: 'Generate', icon: Sparkles, onClick: onGenerate },
    { label: 'Tavily scrape', icon: Globe, onClick: onScrape },
    { label: 'Templates', icon: Library, onClick: onTemplate },
  ];

  return (
    <div className="pointer-events-none fixed inset-x-0 bottom-0 z-20 flex justify-center px-4 pb-6">
      <div className="pointer-events-auto flex items-center gap-2 rounded-full border border-white/70 bg-white/80 p-2 shadow-[0_24px_60px_-30px_rgba(15,23,42,0.35)] backdrop-blur-xl">
        {actions.map(({ label, icon: Icon, onClick, primary }) => (
          <button
            key={label}
            type="button"
            onClick={onClick}
            className={[
              'group flex items-center gap-2 rounded-full px-4 py-3 text-sm font-medium text-slate-600 transition duration-200 hover:scale-[1.03] hover:bg-slate-50 hover:text-slate-900 active:scale-[0.98]',
              primary
                ? 'bg-slate-900 text-white hover:bg-slate-800 hover:text-white'
                : '',
            ].join(' ')}
          >
            <Icon className="size-4 transition-opacity duration-200 group-hover:opacity-90" />
            <span className="hidden md:inline">{label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

'use client';

import { useMemo } from 'react';
import {
  Background,
  BackgroundVariant,
  Controls,
  MiniMap,
  ReactFlow,
} from 'reactflow';

import { useCanvasBoard } from '../../hooks/useCanvasBoard';
import { CanvasCardNode } from './nodes/CanvasCardNode';
import { FloatingToolbar } from './FloatingToolbar';
import { TopNavigation } from './TopNavigation';

export function WorkspaceCanvas() {
  const { nodes, edges, onNodesChange, onEdgesChange, onConnect, actions } =
    useCanvasBoard();

  const nodeTypes = useMemo(
    () => ({
      'canvas-card': CanvasCardNode,
    }),
    [],
  );

  return (
    <div className="relative h-[100dvh] overflow-hidden bg-[radial-gradient(circle_at_top,_rgba(240,249,255,0.95),_rgba(248,250,252,1)_45%,_rgba(255,255,255,1)_100%)] text-slate-900">
      <TopNavigation />

      <main className="h-full pt-24">
        <ReactFlow
          nodes={nodes}
          edges={edges}
          nodeTypes={nodeTypes}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          fitView
          fitViewOptions={{ padding: 0.2 }}
          defaultEdgeOptions={{
            animated: true,
            style: { stroke: '#94a3b8', strokeWidth: 1.5 },
          }}
          proOptions={{ hideAttribution: true }}
          className="!bg-transparent"
        >
          <Background
            variant={BackgroundVariant.Dots}
            gap={20}
            size={1.2}
            color="#cbd5e1"
          />
          <Controls
            position="top-right"
            className="!top-4 !right-4 !rounded-2xl !border !border-slate-200 !bg-white/90 !shadow-lg !backdrop-blur"
          />
          <MiniMap
            pannable
            zoomable
            nodeColor={() => '#e2e8f0'}
            className="!bottom-24 !rounded-2xl !border !border-slate-200 !bg-white/90 !shadow-lg !backdrop-blur"
          />
        </ReactFlow>
      </main>

      <FloatingToolbar
        onAddNote={actions.addQuickNote}
        onAddOwnContent={actions.addOwnContent}
        onGenerate={actions.addGeneratedContent}
        onScrape={actions.addResearchPack}
        onTemplate={actions.addTemplate}
      />
    </div>
  );
}

