          <span className="inline-flex w-fit items-center rounded-full border border-slate-200 bg-white/80 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-600 backdrop-blur">
            {data.badge}
          </span>

          <div className="flex items-start gap-3">
            <div className="flex size-10 items-center justify-center rounded-2xl border border-slate-200 bg-white/85 text-slate-700 shadow-sm">
              <NodeGlyph kind={data.kind} />
            </div>
            <div className="flex flex-1 flex-col gap-1">
              {data.editable ? (
                <input
                  value={data.title}
                  onChange={(event) => data.onUpdate?.({ title: event.target.value })}
                  className="nodrag w-full rounded-xl border border-transparent bg-white/70 px-2 py-1 text-base font-semibold leading-6 text-slate-900 outline-none transition focus:border-slate-200"
