        const type = inferMediaType(file);
        let previewUrl: string | undefined;

        if (supabase) {
          const uploadedAsset = await uploadCanvasAsset(supabase, file, index);
          previewUrl = uploadedAsset.publicUrl;
        } else if (type === 'image' || type === 'video') {
          previewUrl = URL.createObjectURL(file);
          objectUrlsRef.current.push(previewUrl);
        }

        const item: CanvasAssetItem = {
          id: `${file.name}-${index}-${Date.now()}`,
          label: file.name,
          type,
          meta:
            type === 'document'
              ? `${Math.max(1, Math.round(file.size / 1024))} KB document`
              : `${Math.max(1, Math.round(file.size / 1024 / 1024))} MB ${type}`,
          previewUrl,
        };

        nextNodes.push(
          createUploadedAssetNode(
            `asset-${Date.now()}-${index}`,
            getSpawnPosition(-160 + index * 48, 40 + index * 24),
            item,
          ),
        );
      }

      setNodes((currentNodes) => [...currentNodes, ...nextNodes]);
    },
    [getSpawnPosition, setNodes, supabase],
  );

  const addGeneratedContent = useCallback(
    (input: GenerateInput) => {
      const id = `generation-${Date.now()}`;
      addNode(createGenerationNode(id, getSpawnPosition(120, -20), input));
    },
    [addNode, getSpawnPosition],
  );

  const addResearchPack = useCallback(
    (input: TavilyInput) => {
      const noteId = `research-${Date.now()}`;
      const noteNode = createResearchNoteNode(noteId, getSpawnPosition(-160, 0), input);

      if (!input.includeImages) {
        addNode(noteNode);
        return;
      }

      const stackId = `${noteId}-images`;
      const stackNode = createImageStackNode(stackId, getSpawnPosition(180, 60), input.query);

      setNodes((currentNodes) => [...currentNodes, noteNode, stackNode]);
      setEdges((currentEdges) => [
        ...currentEdges,
        {
          id: `edge-${noteId}-${stackId}`,
          source: noteId,
          target: stackId,
          ...edgeDefaults,
        },
      ]);
    },
    [addNode, getSpawnPosition, setEdges, setNodes],
  );

  const addTemplate = useCallback(
    (input: TemplateInput) => {
      const id = `template-${Date.now()}`;
      addNode(createTemplateNode(id, getSpawnPosition(220, 80), input));
    },
    [addNode, getSpawnPosition],
  );

  const onConnect = useCallback(
    (connection: Connection) => {
      setEdges((currentEdges) =>
        addEdge(
          {
            ...connection,
            ...edgeDefaults,
          },
          currentEdges,
        ),
      );
    },
    [setEdges],
  );

  const onEdgeDoubleClick = useCallback(
    (edgeId: string) => {
      setEdges((currentEdges) =>
        currentEdges.filter((edge) => edge.id !== edgeId),
      );
    },
    [setEdges],
  );

  const actions = useMemo(
    () => ({
      addQuickNote,
      addOwnContent,
      addGeneratedContent,
      addResearchPack,
      addTemplate,
      updateNodeData,
    }),
    [addGeneratedContent, addOwnContent, addQuickNote, addResearchPack, addTemplate, updateNodeData],
  );

  return {
    nodes,
    edges,
    onNodesChange,
    onEdgesChange,
    onConnect,
    onEdgeDoubleClick,
    actions,
    persistenceStatus,
    persistenceError,
  };
}

