      : input.type === 'video'
        ? 'Veo video'
        : 'Hera animation',
    input.type === 'image' ? '#fbcfe8' : input.type === 'video' ? '#bfdbfe' : '#ddd6fe',
    input.type === 'image' ? '#fde68a' : input.type === 'video' ? '#67e8f9' : '#f9a8d4',
  );

  return createNode(id, position, {
    kind: 'generation',
    badge: 'Generated Result',
    title:
      input.type === 'image'
        ? 'AI image concept'
        : input.type === 'video'
          ? 'AI video concept'
          : 'AI animation concept',
    subtitle:
      input.type === 'image'
        ? 'Nanobanana mock output'
        : input.type === 'video'
          ? 'Veo mock output'
          : 'Hera mock output',
    accent: 'from-fuchsia-100 via-white to-rose-50',
    prompt: input.prompt,
    assetItems: [
      {
        id: `${id}-asset`,
        label:
          input.type === 'image'
            ? 'generated-image.png'
            : input.type === 'video'
              ? 'generated-video.mp4'
              : 'generated-animation.mp4',
        type: input.type === 'image' ? 'image' : 'video',
        meta:
          input.type === 'image'
            ? 'Sample preview for Nanobanana'
            : input.type === 'video'
              ? 'Sample preview for Veo'
              : 'Sample preview for Hera',
        previewUrl: preview,
      },
    ],
    chips: [input.type, 'Prompted'],
  });
}

export function createResearchNoteNode(
  id: string,
  position: { x: number; y: number },
  input: { query: string; includeImages: boolean },
): CanvasNode {
  return createNode(id, position, {
    kind: 'research',
    badge: 'Tavily Research',
    title: `Research for "${input.query}"`,
    subtitle: 'Mock search output for the canvas',
    accent: 'from-cyan-100 via-white to-blue-50',
    body:
      `Tavily summary for ${input.query}: the strongest pages lean on concrete proof, category-specific phrasing, and people using the product in context.` +
      (input.includeImages
        ? ' Image results were also requested and can be pinned as a stack.'
        : ''),
    bullets: [
      'Winning pages use a sharp problem statement above the fold.',
      'Short comparison blocks and proof screenshots drive trust.',
      'UGC-style visuals outperform isolated packshots for conversion content.',
    ],
    chips: ['Query', input.includeImages ? 'Includes images' : 'Text only'],
  });
}

export function createImageStackNode(
  id: string,
  position: { x: number; y: number },
  query: string,
): CanvasNode {
  return createNode(id, position, {
    kind: 'image-stack',
    badge: 'Selected Images',
    title: `Image picks for "${query}"`,
    subtitle: 'Pinned from search results',
    accent: 'from-slate-100 via-white to-zinc-50',
    stackItems: [
      { label: 'hero lifestyle', tint: 'from-rose-200 to-orange-100' },
