      setPersistenceStatus('loading');
      setPersistenceError(null);

      try {
        const canvas = await loadCanvasState(client);

        if (!isActive) {
          return;
        }

        setNodes(
          canvas.nodes?.length ? sanitizeNodesForStorage(canvas.nodes) : initialNodes,
